SELECT id, drug_id, drug_code, drug_name, location_no, batch_no, category, specification, dosage_form, manufacturer, quantity, unit, purchase_amount, retail_amount, expire_date, warning_stock, created_at, updated_at, deleted FROM clinic_inventory WHERE deleted = 0
AND (drug_code LIKE CONCAT('%', #{keyword}, '%') OR drug_name LIKE CONCAT('%', #{keyword}, '%') OR manufacturer LIKE CONCAT('%', #{keyword}, '%') OR batch_no LIKE CONCAT('%', #{keyword}, '%') OR location_no LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

